INSERT INTO public.document_chunks VALUES (115, 73, 0, '全台灣頂級企業假別制度
一、年度休假制度
 無上限彈性年假（Flexible PTO）
 到職即享有 20 天年假
 鼓勵每年至少休假 20 天以上
二、病假制度
 每年 30 天全薪病假
 心理健康假 5 天
 不需醫師證明
 長期療養假最長 1 年留職留薪
三、家庭照顧與育兒假
 育嬰假最長 2 年
 前 6 個月全薪
 60 天全薪陪產假
 家庭照顧假每年 15 天
四、女性友善假別
 每月 2 天全薪生理假
 凍卵與生殖醫療假 10 天
 流產關懷假 30 天
五、人生重要事件假
 20 天婚假
 一等親喪假 20 天
 寵物喪假 3 天
六、特殊福利假
 生日假
 志工公益假
 學習進修假 15 天
 Sabbatical 三個月全薪長假
七、AI 世代創新假別
 數位排毒假
 創新黑客假
 海外遠端工作假 60 天
八、請假文化規範
 禁止假期羞辱
 禁止主管施壓
 鼓勵 Work-Life Balance
 心理健康優先
